// Function to evaluate the fitness of an individual
double evaluateFitness(double x) {
    return -std::pow(x, 2) + 5 * x + 10;
}

// Generate an initial population of random test data
std::vector<double> generateInitialPopulation(int populationSize, double lowerBound, double upperBound) {
    std::vector<double> population;
    for (int i = 0; i < populationSize; ++i) {
        population.push_back(lowerBound + (upperBound - lowerBound) * static_cast<double>(rand()) / RAND_MAX);
    }
    return population;
}

// Perform selection using tournament selection
double tournamentSelection(std::vector<double>& population, int tournamentSize) {
    int n = population.size();
    int selected = rand() % n;
    for (int i = 0; i < tournamentSize - 1; ++i) {
        int candidate = (rand() % n + selected) % n;
        if (evaluateFitness(population[candidate]) > evaluateFitness(population[selected])) {
            selected = candidate;
        }
    }
    return population[selected];
}

// Perform crossover between two parents
double crossover(double parent1, double parent2, double crossoverPoint) {
    if (rand() % 100 < 50) { // 50% probability of crossover
        return parent1 * (1 - crossoverPoint) + parent2 * crossoverPoint;
    }
    return parent1;
}

